import{_ as o,o as l,c as i,ae as a}from"./chunks/framework.RRduUuAx.js";const p=JSON.parse('{"title":"Merged Fragmented Markdown","description":"","frontmatter":{},"headers":[],"relativePath":"fragemented/worklog/merged.md","filePath":"fragemented/worklog/merged.md"}'),r={name:"fragemented/worklog/merged.md"};function t(d,e,c,n,s,u){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="merged-fragmented-markdown" tabindex="-1">Merged Fragmented Markdown <a class="header-anchor" href="#merged-fragmented-markdown" aria-label="Permalink to &quot;Merged Fragmented Markdown&quot;">​</a></h1><h2 id="source-worklog-index-md" tabindex="-1">Source: worklog/INDEX.md <a class="header-anchor" href="#source-worklog-index-md" aria-label="Permalink to &quot;Source: worklog/INDEX.md&quot;">​</a></h2><h1 id="consolidated-index" tabindex="-1">Consolidated Index <a class="header-anchor" href="#consolidated-index" aria-label="Permalink to &quot;Consolidated Index&quot;">​</a></h1><h2 id="files" tabindex="-1">Files <a class="header-anchor" href="#files" aria-label="Permalink to &quot;Files&quot;">​</a></h2><ul><li><code>INDEX.md</code></li><li><code>WORKLOG_2026-02-21_ADAPTER_FORK_STRATEGY_AND_WEB_RESEARCH.md</code></li><li><code>WORKLOG_2026-02-21_E2E_PLAN_AND_UI_INTEGRATION.md</code></li><li><code>WORKLOG_2026-02-21_MODEL_DB_SEED_NORMALIZATION.md</code></li><li><code>WORKLOG_2026-02-21_UNIFIED_MODEL_PROVIDER_LEDGER_AND_CLIPROXYAPI_FEEDER.md</code></li></ul><h2 id="subdirectories" tabindex="-1">Subdirectories <a class="header-anchor" href="#subdirectories" aria-label="Permalink to &quot;Subdirectories&quot;">​</a></h2><hr><h2 id="source-worklog-worklog-2026-02-21-adapter-fork-strategy-and-web-research-md" tabindex="-1">Source: worklog/WORKLOG_2026-02-21_ADAPTER_FORK_STRATEGY_AND_WEB_RESEARCH.md <a class="header-anchor" href="#source-worklog-worklog-2026-02-21-adapter-fork-strategy-and-web-research-md" aria-label="Permalink to &quot;Source: worklog/WORKLOG_2026-02-21_ADAPTER_FORK_STRATEGY_AND_WEB_RESEARCH.md&quot;">​</a></h2><h1 id="worklog-2026-02-21-adapter-fork-strategy-and-web-research" tabindex="-1">Worklog 2026-02-21: Adapter Fork Strategy and Web Research <a class="header-anchor" href="#worklog-2026-02-21-adapter-fork-strategy-and-web-research" aria-label="Permalink to &quot;Worklog 2026-02-21: Adapter Fork Strategy and Web Research&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>User requested an explicit decision on whether to fork a full Rust monolith versus separate provider-focused solutions, plus a written-down methodology that supports future provider expansion.</p><h2 id="what-was-completed" tabindex="-1">What was completed <a class="header-anchor" href="#what-was-completed" aria-label="Permalink to &quot;What was completed&quot;">​</a></h2><ol><li>Performed wider web scan for:</li></ol><ul><li>multi-provider usage trackers and UI references,</li><li>Rust/Go parser and pipeline candidates,</li><li>performance-oriented crate options for tail/parse/cache/bench.</li></ul><ol start="2"><li>Codified architecture decision:</li></ol><ul><li>no monolithic Rust fork,</li><li>yes to separate provider-focused adapter imports/forks,</li><li><code>tokenledger</code> remains canonical core.</li></ul><ol start="3"><li>Added formal research/policy document:</li></ol><ul><li><code>docs/research/ADAPTER_BASE_LIBS_AND_FORK_STRATEGY_2026-02-21.md</code></li></ul><ol start="4"><li>Captured subscription and token pricing methodology in a unified blended Mtok model, including derivation metadata modes and comparability outputs.</li></ol><h2 id="key-policy-outcome" tabindex="-1">Key policy outcome <a class="header-anchor" href="#key-policy-outcome" aria-label="Permalink to &quot;Key policy outcome&quot;">​</a></h2><ol><li>Provider adapters are replaceable modules that emit normalized JSONL.</li><li>Fork only narrow parser slices when needed, never whole product monoliths.</li><li>Enforce adapter conformance + performance gates under governance.</li><li>Keep pricing derivation transparent and auditable (<code>token</code>, <code>subscription_derived</code>, <code>subscription_manual</code>).</li></ol><h2 id="sources-reviewed-primary" tabindex="-1">Sources reviewed (primary) <a class="header-anchor" href="#sources-reviewed-primary" aria-label="Permalink to &quot;Sources reviewed (primary)&quot;">​</a></h2><ol><li>OpenUsage: <code>https://www.openusage.ai/</code></li><li>CodexBar: <code>https://github.com/steipete/CodexBar</code></li><li>opencode: <code>https://github.com/sst/opencode</code></li><li>ccusage: <code>https://github.com/ryoppippi/ccusage</code></li><li>ccstat: <code>https://crates.io/crates/ccstat</code></li><li>cxusage: <code>https://github.com/johanneserhardt/cxusage</code></li><li>tokscale: <code>https://github.com/junhoyeo/tokscale</code></li></ol><h2 id="next-execution-priorities" tabindex="-1">Next execution priorities <a class="header-anchor" href="#next-execution-priorities" aria-label="Permalink to &quot;Next execution priorities&quot;">​</a></h2><ol><li>Land real adapters (<code>~/.claude</code>, <code>~/.codex</code>, Cursor DB/logs, Droid logs) to normalized JSONL.</li><li>Add per-adapter fixture conformance tests with golden outputs.</li><li>Add benchmark/perf gates for cold backfill, warm tail, and burst ingest in CI.</li><li>Add optional SQLite + disk cache acceleration with bounded overhead.</li></ol><h2 id="closeout-update-implemented" tabindex="-1">Closeout update (implemented) <a class="header-anchor" href="#closeout-update-implemented" aria-label="Permalink to &quot;Closeout update (implemented)&quot;">​</a></h2><ol><li>Adapter coverage is active for Claude/Codex/Cursor (logs + SQLite), ProxyAPI/CLIProxyAPI, and Droid sources in ingest discovery + normalization paths.</li><li>Provider fixture/conformance coverage is present in <code>src/main.rs</code> tests, including adapter-shape normalization and Cursor SQLite deterministic selection/fallback behavior.</li><li>CI benchmark/perf gating added at <code>.github/workflows/bench-perf-gate.yml</code>:</li></ol><ul><li>runs <code>bench --scenario all</code></li><li>enforces strict perf gates via <code>scripts/perf_gate.sh</code> with baseline.</li></ul><ol start="4"><li>Optional SQLite + disk cache acceleration is active via SQLite ingestion path and orchestrate ingest cache controls.</li></ol><hr><h2 id="source-worklog-worklog-2026-02-21-e2e-plan-and-ui-integration-md" tabindex="-1">Source: worklog/WORKLOG_2026-02-21_E2E_PLAN_AND_UI_INTEGRATION.md <a class="header-anchor" href="#source-worklog-worklog-2026-02-21-e2e-plan-and-ui-integration-md" aria-label="Permalink to &quot;Source: worklog/WORKLOG_2026-02-21_E2E_PLAN_AND_UI_INTEGRATION.md&quot;">​</a></h2><h1 id="worklog-2026-02-21-unified-e2e-plan-and-ui-integration" tabindex="-1">Worklog 2026-02-21: Unified E2E Plan and UI Integration <a class="header-anchor" href="#worklog-2026-02-21-unified-e2e-plan-and-ui-integration" aria-label="Permalink to &quot;Worklog 2026-02-21: Unified E2E Plan and UI Integration&quot;">​</a></h1><h2 id="context-1" tabindex="-1">Context <a class="header-anchor" href="#context-1" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>User requested full end-to-end planning and unified docs structure following thegent-style worklog/research organization.</p><h2 id="completed-in-this-cycle" tabindex="-1">Completed in this cycle <a class="header-anchor" href="#completed-in-this-cycle" aria-label="Permalink to &quot;Completed in this cycle&quot;">​</a></h2><ol><li>Added orchestrate-based UI snapshot export for statusbar/extension integration:</li></ol><ul><li><code>--ui-snapshot-path</code></li><li>compact payload with totals, top providers/models, suggestions.</li></ul><ol start="2"><li>Added reconcile governance artifacts:</li></ol><ul><li>per-run reconcile directories,</li><li>reconcile summary outputs,</li><li>rolling latest reconcile summary.</li></ul><ol start="3"><li>Hardened orchestration with additional regression tests around:</li></ol><ul><li>allow-unpriced logic,</li><li>baseline month matching,</li><li>perf gate strict/missing scenario failures.</li></ul><ol start="4"><li>Added and validated docs + task shortcuts for operator workflows.</li></ol><h2 id="planning-outcome-captured" tabindex="-1">Planning outcome captured <a class="header-anchor" href="#planning-outcome-captured" aria-label="Permalink to &quot;Planning outcome captured&quot;">​</a></h2><ol><li>Research artifact:</li></ol><ul><li><code>docs/research/UNIFIED_E2E_RESEARCH_AND_ARCHITECTURE_2026-02-21.md</code></li></ul><ol start="2"><li>Execution plan:</li></ol><ul><li><code>docs/plans/UNIFIED_E2E_EXECUTION_PLAN.md</code></li></ul><ol start="3"><li>Governance policy:</li></ol><ul><li><code>docs/governance/PIPELINE_GOVERNANCE_AND_ARTIFACT_POLICY.md</code></li></ul><ol start="4"><li>Docs indices:</li></ol><ul><li><code>docs/index.md</code></li><li><code>docs/research/INDEX.md</code></li><li><code>docs/plans/INDEX.md</code></li><li><code>docs/worklog/INDEX.md</code></li></ul><h2 id="next-do-all-next-priorities" tabindex="-1">Next do-all-next priorities <a class="header-anchor" href="#next-do-all-next-priorities" aria-label="Permalink to &quot;Next do-all-next priorities&quot;">​</a></h2><ol><li>Implement true Cursor SQLite table parser with deterministic fixtures.</li><li>Add disk-backed caching for normalized events and aggregate views.</li><li>Add pipeline-level summary artifact consolidating ingest/reconcile/report/bench/gate in one JSON.</li></ol><h2 id="closeout-update-implemented-1" tabindex="-1">Closeout update (implemented) <a class="header-anchor" href="#closeout-update-implemented-1" aria-label="Permalink to &quot;Closeout update (implemented)&quot;">​</a></h2><ol><li>Cursor SQLite table-backed ingestion + deterministic selection tests are implemented in <code>src/main.rs</code>.</li><li>Disk-backed ingest caching for orchestrate is implemented via <code>--ingest-cache-path</code> and cache-hit reuse behavior.</li><li>Pipeline-level summary artifact is implemented via <code>--pipeline-summary-path</code> and includes ingest/reconcile/monthly/daily/bench/gate stage results.</li></ol><h2 id="validation-notes" tabindex="-1">Validation notes <a class="header-anchor" href="#validation-notes" aria-label="Permalink to &quot;Validation notes&quot;">​</a></h2><ol><li>Keep using:</li></ol><ul><li><code>cargo fmt --all -- --check</code></li><li><code>cargo clippy --all-targets --all-features -- -D warnings</code></li><li><code>cargo test</code></li><li><code>task do:all:next</code></li><li><code>task orchestrate:ui</code></li></ul><ol start="2"><li>Verify artifacts after each run:</li></ol><ul><li><code>benchmarks/results/reconcile-*/</code></li><li><code>benchmarks/results/reconcile-latest-summary.json</code></li><li><code>benchmarks/results/ui-snapshot.json</code> (when enabled)</li></ul><h2 id="follow-up-closeout-command-reliability" tabindex="-1">Follow-up closeout (command reliability) <a class="header-anchor" href="#follow-up-closeout-command-reliability" aria-label="Permalink to &quot;Follow-up closeout (command reliability)&quot;">​</a></h2><ol><li>Added explicit artifact bootstrap task and dependency wiring:</li></ol><ul><li><code>task artifacts:ensure</code> now creates <code>./artifacts</code> and <code>./benchmarks/results</code> before orchestrate-style task runs.</li><li><code>task do:all:next</code>, <code>task orchestrate</code>, and <code>task orchestrate:ui</code> depend on <code>artifacts:ensure</code>.</li></ul><ol start="2"><li>Moved orchestrate sample ingest output to artifact-managed paths:</li></ol><ul><li><code>--events-out ./artifacts/ingested.sample.jsonl</code> for codex orchestrate flows.</li><li>committed keepfile at <code>artifacts/.gitkeep</code> so artifact output location exists in clean checkouts.</li></ul><ol start="3"><li>Added proxyapi validation shortcuts for fast execution checks:</li></ol><ul><li><code>task ingest:proxyapi:validate</code></li><li><code>task orchestrate:proxyapi:validate</code></li></ul><h2 id="follow-up-closeout-contracts-pricing-governance-ci" tabindex="-1">Follow-up closeout (contracts + pricing governance CI) <a class="header-anchor" href="#follow-up-closeout-contracts-pricing-governance-ci" aria-label="Permalink to &quot;Follow-up closeout (contracts + pricing governance CI)&quot;">​</a></h2><ol><li>Added normalized event schema contract v1:</li></ol><ul><li><code>docs/contracts/NORMALIZED_EVENT_SCHEMA_CONTRACT_V1.md</code></li></ul><ol start="2"><li>Added UI snapshot schema contract v1 with compatibility policy:</li></ol><ul><li><code>docs/contracts/UI_SNAPSHOT_SCHEMA_CONTRACT_V1.md</code></li></ul><ol start="3"><li>Added extension integration examples for file-based consumers:</li></ol><ul><li><code>docs/integrations/EXTENSION_FILE_READ_INTEGRATION_EXAMPLES.md</code></li></ul><ol start="4"><li>Added pricing governance CI workflow:</li></ol><ul><li><code>.github/workflows/pricing-governance-check.yml</code></li><li>stages: <code>pricing-lint</code>, <code>pricing-audit</code>, <code>pricing-check</code></li></ul><ol start="5"><li>Added operator shortcut for local parity with CI:</li></ol><ul><li><code>task pricing:ci</code></li></ul><h2 id="follow-up-closeout-baseline-cache-contract-guards" tabindex="-1">Follow-up closeout (baseline + cache contract guards) <a class="header-anchor" href="#follow-up-closeout-baseline-cache-contract-guards" aria-label="Permalink to &quot;Follow-up closeout (baseline + cache contract guards)&quot;">​</a></h2><ol><li>Added golden baseline lock flow:</li></ol><ul><li><code>task bench:golden:lock</code></li><li><code>task bench:golden:lock:verify</code></li></ul><ol start="2"><li>Bench/perf CI now verifies golden fixture correctness before strict perf gating:</li></ol><ul><li><code>.github/workflows/bench-perf-gate.yml</code></li></ul><ol start="3"><li>Hardened cache contract handling:</li></ol><ul><li>stale ingest cache versions are ignored,</li><li>stale aggregate cache versions are reset to empty before reuse.</li></ul><hr><h2 id="source-worklog-worklog-2026-02-21-model-db-seed-normalization-md" tabindex="-1">Source: worklog/WORKLOG_2026-02-21_MODEL_DB_SEED_NORMALIZATION.md <a class="header-anchor" href="#source-worklog-worklog-2026-02-21-model-db-seed-normalization-md" aria-label="Permalink to &quot;Source: worklog/WORKLOG_2026-02-21_MODEL_DB_SEED_NORMALIZATION.md&quot;">​</a></h2><h1 id="worklog-2026-02-21-model-db-seed-normalization" tabindex="-1">Worklog 2026-02-21: Model DB Seed Normalization <a class="header-anchor" href="#worklog-2026-02-21-model-db-seed-normalization" aria-label="Permalink to &quot;Worklog 2026-02-21: Model DB Seed Normalization&quot;">​</a></h1><h2 id="context-2" tabindex="-1">Context <a class="header-anchor" href="#context-2" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p><code>tokenledger/models.csv</code> was user-pasted baseline data but not valid CSV. It is a markdown-style pipe table and must be treated as text input.</p><h2 id="completed" tabindex="-1">Completed <a class="header-anchor" href="#completed" aria-label="Permalink to &quot;Completed&quot;">​</a></h2><ol><li>Added reproducible generator:</li></ol><ul><li><code>scripts/build_model_seed.py</code></li></ul><ol start="2"><li>Generated review/query artifacts from <code>models.csv</code>:</li></ol><ul><li><code>models_normalized.csv</code> (valid long-format CSV)</li><li><code>models_schema_seed.sql</code> (DDL + inserts for SQL workflows)</li></ul><ol start="3"><li>Added README instructions under:</li></ol><ul><li><code>Model Database Seed (CSV + SQL)</code></li></ul><h2 id="normalization-rules" tabindex="-1">Normalization rules <a class="header-anchor" href="#normalization-rules" aria-label="Permalink to &quot;Normalization rules&quot;">​</a></h2><ol><li>Missing tokens: <code>&#39;&#39;</code>, <code>—</code>, <code>-</code>, <code>N/A</code>, <code>n/a</code>, <code>na</code>, <code>NA</code>, <code>null</code>, <code>NULL</code>.</li><li>Split mixed values once on <code>/</code> into <code>value_primary</code> + <code>value_secondary</code>.</li><li>Preserve raw source token in <code>raw_value</code>.</li><li>Track provenance columns: <code>source_row_index</code>, <code>source_col_index</code>, <code>source_col_name</code>.</li></ol><h2 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h2><ol><li>SQL seed loads in SQLite memory DB.</li><li>Inserted rows match normalized CSV row count.</li></ol><hr><h2 id="source-worklog-worklog-2026-02-21-unified-model-provider-ledger-and-cliproxyapi-feeder-md" tabindex="-1">Source: worklog/WORKLOG_2026-02-21_UNIFIED_MODEL_PROVIDER_LEDGER_AND_CLIPROXYAPI_FEEDER.md <a class="header-anchor" href="#source-worklog-worklog-2026-02-21-unified-model-provider-ledger-and-cliproxyapi-feeder-md" aria-label="Permalink to &quot;Source: worklog/WORKLOG_2026-02-21_UNIFIED_MODEL_PROVIDER_LEDGER_AND_CLIPROXYAPI_FEEDER.md&quot;">​</a></h2><h1 id="worklog-2026-02-21-unified-model-provider-ledger-and-cliproxyapi-feeder" tabindex="-1">Worklog 2026-02-21: Unified Model/Provider Ledger and CLIProxyAPI Feeder <a class="header-anchor" href="#worklog-2026-02-21-unified-model-provider-ledger-and-cliproxyapi-feeder" aria-label="Permalink to &quot;Worklog 2026-02-21: Unified Model/Provider Ledger and CLIProxyAPI Feeder&quot;">​</a></h1><h2 id="context-3" tabindex="-1">Context <a class="header-anchor" href="#context-3" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>User requested a unified model+provider ledger and explicit planning/worklog coverage, with cliproxyapi telemetry as an additional feeder.</p><h2 id="completed-1" tabindex="-1">Completed <a class="header-anchor" href="#completed-1" aria-label="Permalink to &quot;Completed&quot;">​</a></h2><ol><li>Added unified ledger generator:</li></ol><ul><li><code>scripts/build_unified_ledger.py</code></li></ul><ol start="2"><li>Generated deterministic ledger artifacts:</li></ol><ul><li><code>ledger/unified_model_provider_ledger.csv</code></li><li><code>ledger/unified_model_provider_ledger.schema.sql</code></li><li><code>ledger/unified_model_provider_ledger.seed.sql</code></li></ul><ol start="3"><li>Added plan coverage:</li></ol><ul><li>updated <code>docs/plans/UNIFIED_E2E_EXECUTION_PLAN.md</code> with Phase 5 + WP-E</li><li>added <code>docs/plans/UNIFIED_MODEL_PROVIDER_LEDGER_PLAN_2026-02-21.md</code></li></ul><ol start="4"><li>Added index links:</li></ol><ul><li><code>docs/index.md</code></li><li><code>docs/plans/INDEX.md</code></li><li><code>docs/worklog/INDEX.md</code></li></ul><h2 id="ledger-characteristics" tabindex="-1">Ledger characteristics <a class="header-anchor" href="#ledger-characteristics" aria-label="Permalink to &quot;Ledger characteristics&quot;">​</a></h2><ol><li>One-row surface for model/provider joins with:</li></ol><ul><li>pricing fields,</li><li>benchmark prior coverage counts,</li><li>mapping provenance fields (<code>rule</code> + <code>confidence</code>).</li></ul><ol start="2"><li>Deterministic generation from:</li></ol><ul><li><code>pricing.example.json</code></li><li><code>models_normalized.csv</code></li></ul><ol start="3"><li>SQL-loadable schema/seed for DB review and analytics.</li></ol><h2 id="validation-outcomes" tabindex="-1">Validation outcomes <a class="header-anchor" href="#validation-outcomes" aria-label="Permalink to &quot;Validation outcomes&quot;">​</a></h2><ol><li>Generator run produced:</li></ol><ul><li><code>ledger_rows=56</code></li><li><code>priors_aggregation_rows=13</code></li></ul><ol start="2"><li>SQLite load check passed with matching counts.</li></ol><h2 id="feeder-alignment-notes" tabindex="-1">Feeder alignment notes <a class="header-anchor" href="#feeder-alignment-notes" aria-label="Permalink to &quot;Feeder alignment notes&quot;">​</a></h2><ol><li><code>tokenledger</code> now supports <code>proxyapi</code> ingest normalization for OTEL-like span attributes and usage payload shapes.</li><li>Unified ledger plan includes runtime join model for proxyapi-ingested canonical events.</li></ol><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ol><li>Add explicit Pareto scoring view (<code>cost x latency x quality</code>) derived from unified ledger + runtime metrics.</li><li>Wire cliproxyapi management export/metrics snapshot import path into recurring ledger refresh flow.</li><li>Add CI check that regenerates and diff-checks ledger artifacts.</li></ol><h2 id="closeout-update-implemented-2" tabindex="-1">Closeout update (implemented) <a class="header-anchor" href="#closeout-update-implemented-2" aria-label="Permalink to &quot;Closeout update (implemented)&quot;">​</a></h2><ol><li>Pareto scoring artifacts added:</li></ol><ul><li><code>scripts/refresh_ledger.py</code></li><li><code>ledger/unified_model_provider_pareto.csv</code></li><li><code>ledger/unified_model_provider_pareto.view.sql</code></li></ul><ol start="2"><li>CLIProxyAPI snapshot import wired into recurring refresh flow:</li></ol><ul><li>snapshot auto-discovery + explicit <code>--cliproxyapi-snapshot</code> support in <code>scripts/refresh_ledger.py</code></li><li>normalized runtime snapshot export at <code>ledger/cliproxyapi_runtime_metrics_snapshot.csv</code></li></ul><ol start="3"><li>CI diff check added:</li></ol><ul><li><code>.github/workflows/ledger-diff-check.yml</code></li><li>deterministic regeneration command: <code>python3 ./scripts/refresh_ledger.py --allow-missing-snapshot --skip-runtime-discovery</code></li></ul><h2 id="follow-up-closeout-validation-shortcut" tabindex="-1">Follow-up closeout (validation shortcut) <a class="header-anchor" href="#follow-up-closeout-validation-shortcut" aria-label="Permalink to &quot;Follow-up closeout (validation shortcut)&quot;">​</a></h2><ol><li>Added Taskfile SQL validation shortcut for ledger artifacts:</li></ol><ul><li><code>task ledger:sql:validate</code></li><li>loads <code>ledger/unified_model_provider_ledger.schema.sql</code> + <code>ledger/unified_model_provider_ledger.seed.sql</code> into in-memory SQLite and prints <code>ledger_rows=&lt;count&gt;</code>.</li></ul><ol start="2"><li>Exposed this shortcut in operator docs (<code>README.md</code>) under Task shortcuts to make recurring SQL validation explicit and repeatable.</li></ol><hr>',141)])])}const m=o(r,[["render",t]]);export{p as __pageData,m as default};
